const rows = $input.all().map(item => item.json);
const today = new Date();
const todayStr = today.toISOString().split('T')[0];
const weekStartDate = new Date(today);
weekStartDate.setDate(today.getDate() - 6);
const weekStartStr = weekStartDate.toISOString().split('T')[0];

// Filter to last 7 days
const sevenDaysAgo = new Date(today);
sevenDaysAgo.setDate(today.getDate() - 6);
const filtered = rows.filter(row => {
  const date = (row.analyzed_at || row[13] || '').split('T')[0];
  return date >= weekStartStr && date <= todayStr;
});

const byDateCategory = {};
const playerComplaints = {};
const agentScores = {};

for (const row of filtered) {
  const analyzedAt = row.analyzed_at || row[13] || '';
  const date = analyzedAt.split('T')[0];
  const category = row.issue_category || row[5] || 'Other';
  const playerId = row.player_id || row[1] || '';
  const agentName = row.agent_name || row[2] || '';
  const agentScore = parseInt(row.agent_score || row[8] || 3, 10);

  if (!byDateCategory[date]) byDateCategory[date] = {};
  byDateCategory[date][category] = (byDateCategory[date][category] || 0) + 1;

  if (playerId) playerComplaints[playerId] = (playerComplaints[playerId] || 0) + 1;

  if (agentName) {
    if (!agentScores[agentName]) agentScores[agentName] = { total: 0, count: 0, flagged: 0 };
    agentScores[agentName].total += agentScore;
    agentScores[agentName].count++;
    if (agentScore <= 2) agentScores[agentName].flagged++;
  }
}

const allCategories = new Set();
Object.values(byDateCategory).forEach(dayCats => Object.keys(dayCats).forEach(cat => allCategories.add(cat)));

const topIssues = [];
const anomalies = [];

for (const category of allCategories) {
  const dailyCounts = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    const dStr = d.toISOString().split('T')[0];
    dailyCounts.push(byDateCategory[dStr]?.[category] || 0);
  }
  const total7d = dailyCounts.reduce((sum, c) => sum + c, 0);
  const avg7d = total7d / 7;
  const todayCount = dailyCounts[6];
  const pctChange = avg7d > 0 ? Math.round(((todayCount - avg7d) / avg7d) * 100) : 0;
  topIssues.push({ category, count: total7d, today_count: todayCount, daily_avg: Math.round(avg7d * 10) / 10, pct_change: pctChange });
  if (avg7d > 0 && todayCount > avg7d * 1.5) anomalies.push({ category, today_count: todayCount, daily_avg: Math.round(avg7d * 10) / 10, spike_pct: pctChange });
}

topIssues.sort((a, b) => b.count - a.count);

const repeatComplainers = Object.entries(playerComplaints).filter(([, c]) => c >= 3).map(([playerId, count]) => ({ player_id: playerId, complaint_count: count })).sort((a, b) => b.complaint_count - a.complaint_count);

const agentFlags = Object.entries(agentScores).map(([name, data]) => ({ agent_name: name, avg_score: Math.round((data.total / data.count) * 10) / 10, conversation_count: data.count, flag_rate: Math.round((data.flagged / data.count) * 100) })).filter(a => a.flag_rate > 20 || a.avg_score < 3).sort((a, b) => a.avg_score - b.avg_score);

return [{ json: { week_start: weekStartStr, week_end: todayStr, top_issues_json: JSON.stringify(topIssues), anomalies_json: JSON.stringify(anomalies), repeat_complainers: repeatComplainers.length, repeat_complainers_detail: repeatComplainers, agent_flags_json: JSON.stringify(agentFlags), has_anomalies: anomalies.length > 0, total_rows: filtered.length } }];

