const claudeResponse = $input.first().json;
const trendData = $('Calculate Trends').first().json;
const content = claudeResponse.content?.[0]?.text || 'No trend summary generated';
const parts = content.split('RECOMMENDATIONS');
const trendSummary = parts[0].replace('TREND SUMMARY', '').trim();
const recommendations = parts[1] ? parts[1].trim() : '';
return [{ json: { week_start: trendData.week_start, week_end: trendData.week_end, top_issues_json: trendData.top_issues_json, anomalies_json: trendData.anomalies_json, repeat_complainers: trendData.repeat_complainers, trend_summary: trendSummary, recommendations, has_anomalies: trendData.has_anomalies } }];

const trendData = $('Calculate Trends').first().json;
const anomalies = JSON.parse(trendData.anomalies_json || '[]');
const anomalyText = anomalies.length > 0 ? anomalies.map(a => `• *${a.category}*: ${a.today_count} today vs ${a.daily_avg} avg (+${a.spike_pct}%)`).join('\n') : '_No anomalies_';
const blocks = [{ type: 'header', text: { type: 'plain_text', text: ':chart_with_upwards_trend: 7-Day QA Trend Report', emoji: true } }, { type: 'section', text: { type: 'mrkdwn', text: `*Period:* ${trendData.week_start} -> ${trendData.week_end} | *Anomalies:* ${anomalies.length} | *Repeat Complainers:* ${trendData.repeat_complainers}` } }, { type: 'section', text: { type: 'mrkdwn', text: `*Spiking Categories:*\n${anomalyText}` } }, { type: 'context', elements: [{ type: 'mrkdwn', text: 'Full trend analysis stored in weekly_trends table' }] }];
const input = $input.first().json;
return [{ json: { blocks, text: `7-Day QA Trends: ${anomalies.length} anomalies detected. Repeat complainers: ${trendData.repeat_complainers}`, trend_data: trendData, trend_summary: input.trend_summary || '', recommendations: input.recommendations || '' } }];
